import math

class Calculator:
    def add(self, x, y):
        return x + y

    def subtract(self, x, y):
        return x - y

    def multiply(self, x, y):
        return x * y

    def divide(self, x, y):
        if y == 0:
            return "Cannot divide by zero"
        return x / y

    def power(self, x, y):
        return x ** y

    def sqrt(self, x):
        if x < 0:
            return "Cannot calculate square root of a negative number"
        return math.sqrt(x)

    def log(self, x, base):
        if x <= 0 or base <= 0 or base == 1:
            return "Invalid input for logarithm"
        return math.log(x, base)

    def factorial(self, x):
        if not isinstance(x, int) or x < 0:
            return "Factorial is only defined for non-negative integers"
        if x == 0:
            return 1
        else:
            result = 1
            for i in range(1, x + 1):
                result *= i
            return result

    def sin(self, x):
        return math.sin(x)

    def cos(self, x):
        return math.cos(x)

    def tan(self, x):
        return math.tan(x)

    def asin(self, x):
        if not -1 <= x <= 1:
            return "Invalid input for arcsin (must be between -1 and 1)"
        return math.asin(x)

    def acos(self, x):
        if not -1 <= x <= 1:
            return "Invalid input for arccos (must be between -1 and 1)"
        return math.acos(x)

    def atan(self, x):
        return math.atan(x)

    def nth_root(self, x, n):
        if n == 0:
            return "Cannot calculate root with n = 0"
        if x < 0 and n % 2 == 0:
            return "Cannot calculate even root of a negative number"
        return x ** (1/n)

